/**
 * Deletes auto-generated calendar events that were created by the submissions,
 * evaluations, and reports workflows. These are notification-style events that
 * should never have been added to the calendar.
 *
 * Safe to run multiple times — only deletes rows matching the known patterns.
 *
 * Usage:
 *   node server/scripts/cleanup-autogenerated-calendar-events.js
 */

const { supabaseAdmin } = require('../src/config/supabase');

const TITLE_PATTERNS = [
  'Review Result: %',
  'Re-review: %',
  'Review: %',
  '% Evaluation Submitted — Group %',
  'Review Weekly Report #%',
];

async function main() {
  console.log('Cleaning up auto-generated calendar events...\n');

  let totalDeleted = 0;

  for (const pattern of TITLE_PATTERNS) {
    const { data, error } = await supabaseAdmin
      .from('calendar_events')
      .delete()
      .like('title', pattern)
      .select('id, title, date');

    if (error) {
      console.error(`  ✗ Failed for pattern "${pattern}":`, error.message);
      continue;
    }

    const count = data?.length ?? 0;
    totalDeleted += count;

    if (count > 0) {
      console.log(`  ✓ Deleted ${count} event(s) matching "${pattern}":`);
      data.forEach((e) => console.log(`      - [${e.date}] ${e.title}`));
    } else {
      console.log(`  – No events matched "${pattern}"`);
    }
  }

  console.log(`\nDone. Total deleted: ${totalDeleted}`);
  process.exit(0);
}

main().catch((err) => {
  console.error('Unexpected error:', err);
  process.exit(1);
});
